@namespace sv_585540fd7cea446eac78c84e882d1186.Components.Pages.Settings

<nav class="settings-sidebar" role="tablist" aria-label="Settings sections">
    @foreach (var section in _sections)
    {
        <button type="button"
                role="tab"
                class="sidebar-item @(ActiveSection == section.Key ? "active" : "")"
                aria-selected="@(ActiveSection == section.Key)"
                @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
            <span class="sidebar-icon">@section.Icon</span>
            <span class="sidebar-label">@section.Label</span>
        </button>
    }
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@namespace sv_585540fd7cea446eac78c84e882d1186.Components.Pages.Settings
@using sv_585540fd7cea446eac78c84e882d1186.Models
@using sv_585540fd7cea446eac78c84e882d1186.Services
@inject ISettingsService SettingsService

<section class="settings-section" aria-labelledby="profile-heading">
    <h2 id="profile-heading">Profile</h2>

    @if (_loading)
    {
        <p class="loading-text">Loading profile…</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar preview" />
                </div>
                <label class="form-label">
                    Avatar URL
                    <input type="url" class="form-control" @bind="_avatarUrl" />
                </label>
            </div>

            <label class="form-label">
                Display Name
                <input type="text" class="form-control" @bind="_displayName" />
            </label>

            <label class="form-label">
                Email
                <input type="email" class="form-control" @bind="_email" />
            </label>

            <label class="form-label">
                Bio
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </label>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
            </div>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success toast-message" role="status">@_successMessage</div>
            }
        </div>
    }
</section>

@code {
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        _successMessage = "Profile saved successfully!";
        _ = ClearMessageAfterDelay();
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        _successMessage = null;
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_585540fd7cea446eac78c84e882d1186.Components.Pages.Settings
@using sv_585540fd7cea446eac78c84e882d1186.Models
@using sv_585540fd7cea446eac78c84e882d1186.Services
@inject ISettingsService SettingsService

<section class="settings-section" aria-labelledby="notif-heading">
    <h2 id="notif-heading">Notifications</h2>

    @if (_loading)
    {
        <p class="loading-text">Loading notification preferences…</p>
    }
    else
    {
        <div class="notification-form">
            <div class="toggle-group">
                <label class="toggle-row">
                    <span>Email Notifications</span>
                    <input type="checkbox" class="form-check-input toggle-switch" @bind="_emailNotifications" />
                </label>

                <label class="toggle-row">
                    <span>Push Notifications</span>
                    <input type="checkbox" class="form-check-input toggle-switch" @bind="_pushNotifications" />
                </label>

                <label class="toggle-row">
                    <span>Weekly Digest</span>
                    <input type="checkbox" class="form-check-input toggle-switch" @bind="_weeklyDigest" />
                </label>
            </div>

            <h3>Muted Channels</h3>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               class="form-check-input"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <span>@channel</span>
                    </label>
                }
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Preferences")
                </button>
            </div>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success toast-message" role="status">@_successMessage</div>
            }
        </div>
    }
</section>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        if (SettingsService is MockSettingsService mock)
        {
            _allChannels = mock.GetAllChannels();
        }

        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var prefs = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _successMessage = "Preferences saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_585540fd7cea446eac78c84e882d1186.Components.Pages.Settings
@using sv_585540fd7cea446eac78c84e882d1186.Models
@using sv_585540fd7cea446eac78c84e882d1186.Services
@inject ISettingsService SettingsService

<section class="settings-section" aria-labelledby="security-heading">
    <h2 id="security-heading">Security</h2>

    @if (_loading)
    {
        <p class="loading-text">Loading security settings…</p>
    }
    else
    {
        <!-- Change Password Panel -->
        <div class="expandable-panel">
            <button type="button"
                    class="panel-header"
                    aria-expanded="@_passwordExpanded"
                    @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordExpanded ? "▲" : "▼")</span>
            </button>

            @if (_passwordExpanded)
            {
                <div class="panel-body">
                    <label class="form-label">
                        Current Password
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </label>
                    <label class="form-label">
                        New Password
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </label>
                    <label class="form-label">
                        Confirm Password
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </label>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger" role="alert">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="alert alert-success" role="status">@_passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating…" : "Update Password")
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="tfa-section">
            <label class="toggle-row">
                <span>
                    Two-Factor Authentication
                    <span class="status-badge @(_twoFactorEnabled ? "status-on" : "status-off")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </span>
                <input type="checkbox" class="form-check-input toggle-switch" @bind="_twoFactorEnabled" />
            </label>
            @if (_security?.LastPasswordChange is not null)
            {
                <p class="hint-text">Last password change: @_security.LastPasswordChange.Value.ToString("MMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="sessions-section">
            <h3>Active Sessions</h3>
            <div class="table-responsive">
                <table class="table">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td>
                                    @if (session.Id != _sessions.FirstOrDefault()?.Id)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-success">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop" @onclick="CancelRevoke"></div>
            <div class="confirmation-dialog" role="dialog" aria-modal="true" aria-label="Confirm session revocation">
                <h4>Revoke Session</h4>
                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                <div class="dialog-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                        @(_revoking ? "Revoking…" : "Revoke")
                    </button>
                    <button class="btn btn-outline-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        }
    }
</section>

@code {
    private bool _loading = true;
    private SecuritySettings? _security;
    private List<ActiveSession> _sessions = [];
    private bool _twoFactorEnabled;

    // Password change
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;
    private string? _passwordSuccess;

    // Revoke dialog
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessions = [.. _security.Sessions];
        _twoFactorEnabled = _security.TwoFactorEnabled;
        _loading = false;
