    {
        <p class="loading-text">Loading appearance settings…</p>
    }
    else
    {
        <div class="appearance-form">
            <!-- Theme -->
            <fieldset>
                <legend>Theme</legend>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-item">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Font Size -->
            <fieldset>
                <legend>Font Size</legend>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-item">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Language -->
            <label class="form-label">
                Language
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </label>

            <!-- Compact Mode -->
            <label class="toggle-row">
                <span>Compact Mode</span>
                <input type="checkbox" class="form-check-input toggle-switch" @bind="_compactMode" />
            </label>

            <!-- Live Preview -->
            <div class="preview-area @GetPreviewClasses()">
                <h4 class="preview-title">Live Preview</h4>
                <p class="preview-text">
                    This is a preview of your appearance settings. The background, text size, and spacing
                    reflect your current choices.
                </p>
                <div class="preview-card">
                    <strong>Sample Card</strong>
                    <span>Theme: @_theme · Font: @_fontSize · Language: @_language</span>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>

