@namespace sv_585540fd7cea446eac78c84e882d1186.Components.Pages.Settings
@using sv_585540fd7cea446eac78c84e882d1186.Models
@using sv_585540fd7cea446eac78c84e882d1186.Services
@inject ISettingsService SettingsService

<section class="settings-section" aria-labelledby="appearance-heading">
    <h2 id="appearance-heading">Appearance</h2>

    @if (_loading)
    {
        <p class="loading-text">Loading appearance settings…</p>
    }
    else
    {
        <div class="appearance-form">
            <!-- Theme -->
            <fieldset>
                <legend>Theme</legend>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-item">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Font Size -->
            <fieldset>
                <legend>Font Size</legend>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-item">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Language -->
            <label class="form-label">
                Language
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </label>

            <!-- Compact Mode -->
            <label class="toggle-row">
                <span>Compact Mode</span>
                <input type="checkbox" class="form-check-input toggle-switch" @bind="_compactMode" />
            </label>

            <!-- Live Preview -->
            <div class="preview-area @GetPreviewClasses()">
                <h4 class="preview-title">Live Preview</h4>
                <p class="preview-text">
                    This is a preview of your appearance settings. The background, text size, and spacing
                    reflect your current choices.
                </p>
                <div class="preview-card">
                    <strong>Sample Card</strong>
                    <span>Theme: @_theme · Font: @_fontSize · Language: @_language</span>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success toast-message" role="status">@_successMessage</div>
            }
        </div>
    }
</section>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_theme.ToLowerInvariant()} preview-font-{_fontSize.ToLowerInvariant()}";
        if (_compactMode) classes += " preview-compact";
        return classes;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        await SettingsService.SaveAppearanceAsync(new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        _successMessage = "Appearance saved!";
        _ = ClearMessageAfterDelay();
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

