@page "/settings"
@namespace sv_585540fd7cea446eac78c84e882d1186.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

arguments.file_text:
.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* ── Sidebar ── */
.settings-sidebar {
    display: flex;
    flex-direction: column;
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.625rem;
    padding: 0.75rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
}
.sidebar-item:hover {
    background: #e9ecef;
}
.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}
.sidebar-icon {
    font-size: 1.15rem;
}

/* ── Content area ── */
.settings-content {
    flex: 1;
    padding: 2rem 2.5rem;
    max-width: 800px;
}

.settings-section h2 {
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    font-weight: 600;
}
.settings-section h3 {
    margin-top: 1.5rem;
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
    font-weight: 600;
}

.loading-text {
    color: #6c757d;
    font-style: italic;
}

/* ── Form elements ── */
.form-label {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    margin-bottom: 1rem;
    font-weight: 500;
    font-size: 0.9rem;
    color: #495057;
}
.form-control,
.form-select {
    margin-top: 0.125rem;
}

.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
}

/* ── Toggle rows ── */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}
.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
    cursor: pointer;
    font-weight: 500;
    font-size: 0.95rem;
}
.toggle-switch {
    width: 2.5rem !important;
    height: 1.25rem !important;
    cursor: pointer;
}

/* ── Toast / alert ── */
.toast-message {
    margin-top: 1rem;
    animation: fadeIn 0.25s ease;
}
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Profile avatar ── */
.avatar-area {
    display: flex;
    align-items: flex-start;
    gap: 1.25rem;
    margin-bottom: 1rem;
}
.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    flex-shrink: 0;
}
.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}
.avatar-area .form-label {
    flex: 1;
}

/* ── Channel list ── */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}
.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0;
    font-size: 0.9rem;
    cursor: pointer;
    text-transform: capitalize;
}

/* ── Expandable panel ── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    margin-bottom: 1.25rem;
    overflow: hidden;
}
.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.85rem 1rem;
    background: #f8f9fa;
    border: none;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
}
.panel-header:hover {
    background: #e9ecef;
}
.expand-icon {
    font-size: 0.75rem;
    color: #6c757d;
}
.panel-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ── Status badges ── */
.status-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 1rem;
    font-size: 0.75rem;
    font-weight: 600;
    margin-left: 0.5rem;
    vertical-align: middle;
}
.status-on {
    background: #d1e7dd;
    color: #0f5132;
}
.status-off {
    background: #f8d7da;
    color: #842029;
}

.tfa-section {
    margin-bottom: 1.5rem;
